from pydantic import BaseModel, field_validator, ValidationInfo
from typing import List

class Product(BaseModel):
    sku: str
    price: float
    tags: List[str] = []

    @field_validator('tags', mode='before')
    @classmethod
    def normalize_tags(cls, v, values):  # BUG: pydantic v2 expects (cls, v, info), not (cls, v, values)
        if isinstance(v, str):
            # Old v1 code that assumed ``values`` is a dict of sibling fields
            return [t.strip().lower() for t in values.get('tags', '').split(',')]
        return v

if __name__ == '__main__':
    bad = Product(sku="a1", price="19.99", tags="premium")
    print(bad)
